@app.route("/api/v1/tables", methods=["GET"])
@require_api_key
def list_tables():
    """List all allowed tables and their columns."""
    conn = None
    try:
        conn = get_db_connection()
        tables_info = {}
        for table in ALLOWED_TABLES:
            columns = get_table_columns(conn, "public", table)
            if columns:
                tables_info[table] = sorted(list(columns))

        return jsonify({"tables": tables_info}), 200

    except psycopg2.Error as e:
        app.logger.error(f"Database error: {e}")
        return jsonify({"error": "A database error occurred."}), 500
    finally:
        if conn:
            conn.close()


@app.route("/api/v1/tables/<table_name>/schema", methods=["GET"])
@require_api_key
def table_schema(table_name):
    """Get detailed schema information for a specific table."""
    valid, err = validate_table_name(table_name)
    if not valid:
        return jsonify({"error": err}), 400

    conn = None
    try:
        conn = get_db_connection()
        query = sql.SQL(
            """
            SELECT column_name, data_type, is_nullable, column_default, character_maximum_length
            FROM information_schema.columns
            WHERE table_schema = %s AND table_name = %s
            ORDER BY ordinal_position
            """
        )
        with conn.cursor(cursor_factory=psycopg2.extras.RealDictCursor) as cur:
            cur.execute(query, ("public", table_name))
            columns = [dict(row) for row in cur.fetchall()]

        if not columns:
            return jsonify({"error": f"Table '{table_name}' not found."}), 404

        return jsonify({
            "table": table_name,
            "columns": columns,
        }), 200

    except psycopg2.Error as e:
        app.logger.error(f"Database error: {e}")
        return jsonify({"error": "A database error occurred."}), 500
    finally:
        if conn:
            conn.close()


@app.route("/api/v1/aggregate", methods=["POST"])
@require_api_key
def aggregate_query():
    """
    Aggregation endpoint.
    
    Request body (JSON):
    {
        "table": "orders",
        "aggregations": [
            {"function": "count", "column": "*", "alias": "total_orders"},
            {"function": "sum", "column": "amount", "alias": "total_amount"},
            {"function": "avg", "column": "amount", "alias": "avg_amount"}
        ],
        "group_by": ["status", "region"],          // optional
        "filters": [...],                           // optional, same format as /query
        "order_by": "total_amount",                 // can reference aliases
        "order_dir": "desc",
        "limit": 100
    }
    """
    ALLOWED_AGG_FUNCTIONS = {"count", "sum", "avg", "min", "max"}

    if not request.is_json:
        return jsonify({"error": "Content-Type must be application/json."}), 400

    data = request.get_json()
    if not data:
        return jsonify({"error": "Request body is required."}), 400

    table_name = data.get("table")
    if not table_name:
        return jsonify({"error": "Field 'table' is required."}), 400

    valid, err = validate_table_name(table_name)
    if not valid:
        return jsonify({"error": err}), 400

    schema = data.get("schema", "public")
    if not validate_identifier(schema):
        return jsonify({"error": "Invalid schema name."}), 400

    aggregations = data.get("aggregations", [])
    if not aggregations or not isinstance(aggregations, list):
        return jsonify({"error": "'aggregations' must be a non-empty list."}), 400

    conn = None
    try:
        conn = get_db_connection()
        available_columns = get_table_columns(conn, schema, table_name)

        if not available_columns:
            return jsonify({"error": f"Table '{table_name}' not found."}), 404

        # Parse filters
        raw_filters = data.get("filters", [])
        filters, err = parse_filters(raw_filters, available_columns)
        if err:
            return jsonify({"error": err}), 400

        # Validate group_by
        group_by = data.get("group_by", [])
        if group_by:
            if not isinstance(group_by, list):
                return jsonify({"error": "'group_by' must be a list."}), 400
            valid, err = validate_columns(group_by, available_columns)
            if not valid:
                return jsonify({"error": err}), 400

        # Build aggregation SELECT parts
        select_parts = []
        alias_set = set()

        for gb_col in group_by:
            select_parts.append(sql.Identifier(gb_col))

        for i, agg in enumerate(aggregations):
            func = agg.get("function", "").lower()
            col = agg.get("column", "")
            alias = agg.get("alias", f"agg_{i}")

            if func not in ALLOWED_AGG_FUNCTIONS:
                return jsonify({"error": f"Invalid aggregation function '{func}'. Allowed: {list(ALLOWED_AGG_FUNCTIONS)}"}), 400

            if not validate_identifier(alias):
                return jsonify({"error": f"Invalid alias '{alias}'."}), 400

            if alias in alias_set:
                return jsonify({"error": f"Duplicate alias '{alias}'."}), 400
            alias_set.add(alias)

            if col == "*":
                if func != "count":
                    return jsonify({"error": f"Only COUNT can use '*' as column."}), 400
                select_parts.append(
                    sql.SQL("COUNT(*) AS {}").format(sql.Identifier(alias))
                )
            else:
                if not validate_identifier(col) or col not in available_columns:
                    return jsonify({"error": f"Invalid column '{col}' in aggregation at index {i}."}), 400
                func_sql = sql.SQL(func.upper())
                select_parts.append(
                    sql.SQL("{}({}) AS {}").format(func_sql, sql.Identifier(col), sql.Identifier(alias))
                )

        # Build query
        params = []
        table_ref = sql.SQL("{}.{}").format(
            sql.Identifier(schema),
            sql.Identifier(table_name)
        )

        query_parts = [
            sql.SQL("SELECT "),
            sql.SQL(", ").join(select_parts),
            sql.SQL(" FROM "),
            table_ref,
        ]

        # WHERE
        where_clauses = []
        for f in filters:
            col_ident = sql.Identifier(f["column"])
            if not f["needs_value"]:
                where_clauses.append(
                    sql.SQL("{} {}").format(col_ident, sql.SQL(f["operator"]))
                )
            else:
                where_clauses.append(
                    sql.SQL("{} {} %s").format(col_ident, sql.SQL(f["operator"]))
                )
                params.append(f["value"])

        if where_clauses:
            query_parts.append(sql.SQL(" WHERE "))
            query_parts.append(sql.SQL(" AND ").join(where_clauses))

        # GROUP BY
        if group_by:
            query_parts.append(sql.SQL(" GROUP BY "))
            query_parts.append(
                sql.SQL(", ").join(sql.Identifier(col) for col in group_by)
            )

        # ORDER BY - can be a group_by column or an alias
        order_by = data.get("order_by")
        if order_by:
            valid_order_targets = set(group_by) | alias_set
            if not validate_identifier(order_by) or order_by not in valid_order_targets:
                return jsonify({"error": f"Invalid order_by: '{order_by}'. Must be a group_by column or aggregation alias."}), 400

            order_dir = data.get("order_dir", "asc").lower()
            if order_dir not in ALLOWED_ORDER_DIRECTIONS:
                return jsonify({"error": "order_dir must be 'asc' or 'desc'."}), 400

            direction = sql.SQL(" ASC") if order_dir == "asc" else sql.SQL(" DESC")
            query_parts.append(sql.SQL(" ORDER BY "))
            query_parts.append(sql.Identifier(order_by))
            query_parts.append(direction)

        # LIMIT
        try:
            limit = int(data.get("limit", DEFAULT_LIMIT))
        except (ValueError, TypeError):
            return jsonify({"error": "limit must be an integer."}), 400

        if limit < 1 or limit > MAX_LIMIT:
            return jsonify({"error": f"limit must be between 1 and {MAX_LIMIT}."}), 400

        query_parts.append(sql.SQL(" LIMIT %s"))
        params.append(limit)

        query = sql.Composed(query_parts)

        with conn.cursor(cursor_factory=psycopg2.extras.RealDictCursor) as cur:
            cur.execute(query, params)
            rows = cur.fetchall()
            results = [dict(row) for row in rows]

        return jsonify({
            "table": table_name,
            "aggregations": [a.get("alias", f"agg_{i}") for i, a in enumerate(aggregations)],
            "group_by": group_by,
            "rows_returned": len(results),
            "data": results,
        }), 200

    except psycopg2.Error as e:
        app.logger.error(f"Database error: {e}")
        return jsonify({"error": "A database error occurred."}), 500
    except Exception as e:
        app.logger.error(f"Unexpected error: {e}")
        return jsonify({"error": "An internal error occurred."}), 500
    finally:
        if conn:
            conn.close()


